// T99 SeatReservationHandler — CORRECT ordering
async handle(input: PurchaseInput): Promise<DataProcessResult<TicketResult>> {
  // Step 1: Reserve seat with TTL BEFORE payment
  const holdResult = await this.capacityLock.reserveSeat({
    eventId: input.eventId,
    userId: input.userId,
    ttlSeconds: 300, // 5-minute hold
  });
  if (!holdResult.isSuccess) {
    return DataProcessResult.failure('SEAT_UNAVAILABLE', 'No seats available');
  }
  // DNA-8: storeDocument BEFORE enqueue
  await this.db.storeDocument('ticket-purchases', { status: 'PENDING', holdId: holdResult.data.holdId, knowledgeScope: 'PRIVATE' }, purchaseId);
  // Step 2: Enqueue payment AFTER seat hold confirmed
  await this.queue.enqueue('payment.process.requested', { purchaseId, holdId: holdResult.data.holdId });
  return DataProcessResult.success({ purchaseId, status: 'PAYMENT_PENDING' });
}
